    size_t bytes_read;
    while ((bytes_read = fread(buffer, 1, sizeof(buffer), file)) > 0) {
        err = nvs_set_blob(handle, "firmware", buffer, bytes_read);
        if (err != ESP_OK) {
            printf("Failed to write firmware to NVS: %s\n", esp_err_to_name(err));
            break;
        }
    }

    fclose(file);
